void main() {
  group('SpeakerRole interface', () {
    test('values are dreamfinder and user', () {
      expect(SpeakerRole.values.length, 2);
      expect(SpeakerRole.values, contains(SpeakerRole.dreamfinder));
      expect(SpeakerRole.values, contains(SpeakerRole.user));
