      expect(SpeakerRole.tryParse(''), isNull);
    });

    test('tryParse returns null for null input', () {
      expect(SpeakerRole.tryParse(null), isNull);
    });

    test('wire strings are non-empty', () {
      for (final role in SpeakerRole.values) {
        expect(role.wire, isNotEmpty);
      }
    });

    test('all wire strings are unique', () {
      final wires = SpeakerRole.values.map((r) => r.wire).toSet();
      expect(wires.length, SpeakerRole.values.length);
